using System.ComponentModel.DataAnnotations;

namespace sv_81d08607bd434ee4ac4c97e5d3902cb1.Models;

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100, MinimumLength = 1, ErrorMessage = "Name must be between 1 and 100 characters.")]
    public string Name { get; set; } = string.Empty;

    [Required(ErrorMessage = "Quantity is required.")]
    [Range(0, int.MaxValue, ErrorMessage = "Quantity must be 0 or greater.")]
    public int Quantity { get; set; }

    [Required(ErrorMessage = "Unit Price is required.")]
    [Range(0.01, double.MaxValue, ErrorMessage = "Unit Price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public ProductCategory Category { get; set; }
}

public enum ProductCategory
{
    Electronics,
    Clothing,
    Food,
    Other
}

using sv_81d08607bd434ee4ac4c97e5d3902cb1.Models;

namespace sv_81d08607bd434ee4ac4c97e5d3902cb1.Services;

public class InventoryService
{
    private readonly List<Product> _products;
    private readonly Lock _lock = new();
    private int _nextId;

    public InventoryService()
    {
        _products = new List<Product>
        {
            new() { Id = 1, Name = "Wireless Headphones", Quantity = 45, UnitPrice = 79.99m, Category = ProductCategory.Electronics },
            new() { Id = 2, Name = "Cotton T-Shirt", Quantity = 200, UnitPrice = 19.99m, Category = ProductCategory.Clothing },
            new() { Id = 3, Name = "Organic Coffee Beans", Quantity = 80, UnitPrice = 14.50m, Category = ProductCategory.Food },
            new() { Id = 4, Name = "USB-C Charging Cable", Quantity = 150, UnitPrice = 12.99m, Category = ProductCategory.Electronics },
            new() { Id = 5, Name = "Winter Jacket", Quantity = 30, UnitPrice = 129.99m, Category = ProductCategory.Clothing },
            new() { Id = 6, Name = "Dried Pasta Pack", Quantity = 300, UnitPrice = 3.49m, Category = ProductCategory.Food },
        };
        _nextId = 7;
    }

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_products.Select(p => Clone(p)).ToList());
        }
    }

    public Task AddAsync(Product product)
    {
        lock (_lock)
        {
            product.Id = _nextId++;
            _products.Add(Clone(product));
        }
        return Task.CompletedTask;
    }

    public Task UpdateAsync(Product product)
    {
        lock (_lock)
        {
            var index = _products.FindIndex(p => p.Id == product.Id);
            if (index >= 0)
            {
                _products[index] = Clone(product);
            }
        }
        return Task.CompletedTask;
    }

    private static Product Clone(Product p) => new()
    {
        Id = p.Id,
        Name = p.Name,
        Quantity = p.Quantity,
        UnitPrice = p.UnitPrice,
        Category = p.Category
    };
}

@page "/inventory"
@using sv_81d08607bd434ee4ac4c97e5d3902cb1.Models
@using sv_81d08607bd434ee4ac4c97e5d3902cb1.Services
@inject InventoryService InventoryService

<PageTitle>Inventory</PageTitle>

<h1>Inventory Management</h1>

@* PART 1: Quick Add — Static SSR form, no rendermode on this page *@
<div class="card mb-4">
    <div class="card-header">
        <h5 class="mb-0">Quick Add Product</h5>
    </div>
    <div class="card-body">
        <EditForm Model="NewProduct" FormName="QuickAddProduct" method="post" OnValidSubmit="AddProduct">
            <DataAnnotationsValidator />
            <ValidationSummary />
            <div class="row g-3 align-items-end">
                <div class="col-md-3">
                    <label class="form-label">Name</label>
                    <InputText class="form-control" @bind-Value="NewProduct.Name" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Quantity</label>
                    <InputNumber class="form-control" @bind-Value="NewProduct.Quantity" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Unit Price</label>
                    <InputNumber class="form-control" @bind-Value="NewProduct.UnitPrice" />
                </div>
                <div class="col-md-2">
                    <label class="form-label">Category</label>
                    <InputSelect class="form-select" @bind-Value="NewProduct.Category">
                        @foreach (var cat in Enum.GetValues<ProductCategory>())
                        {
                            <option value="@cat">@cat</option>
                        }
                    </InputSelect>
                </div>
                <div class="col-md-2">
                    <button type="submit" class="btn btn-primary">Add Product</button>
                </div>
            </div>
        </EditForm>
    </div>
</div>

@* PART 2: Product table with inline editing via interactive component *@
<table class="table table-striped">
    <thead>
        <tr>
            <th>Name</th>
            <th>Quantity</th>
            <th>Unit Price</th>
            <th>Category</th>
            <th>Actions</th>
        </tr>
    </thead>
    <tbody>
        @foreach (var product in Products)
        {
            <EditProductRow Product="product" @rendermode="InteractiveServer" />
        }
    </tbody>
</table>

@code {
    [SupplyParameterFromForm]
    private Product NewProduct { get; set; } = new();

    private List<Product> Products { get; set; } = new();

    protected override async Task OnInitializedAsync()
    {
        Products = await InventoryService.GetAllAsync();
    }

    private async Task AddProduct()
    {
        await InventoryService.AddAsync(NewProduct);
        NewProduct = new();
        Products = await InventoryService.GetAllAsync();
    }
}

