@code {
    [Parameter]
    public Product Product { get; set; } = default!;

    private bool _isEditing;
    private Product _editModel = new();

    private void StartEdit()
    {
        _editModel = new Product
        {
            Id = Product.Id,
            Name = Product.Name,
            Quantity = Product.Quantity,
            UnitPrice = Product.UnitPrice,
            Category = Product.Category
        };
        _isEditing = true;
    }

    private async Task Save()
    {
        await InventoryService.UpdateAsync(_editModel);
        Product.Name = _editModel.Name;
        Product.Quantity = _editModel.Quantity;
        Product.UnitPrice = _editModel.UnitPrice;
        Product.Category = _editModel.Category;
        _isEditing = false;
    }

    private void Cancel()
    {
        _isEditing = false;
    }
}

